esqlQuery.esql:
FROM metrics-redisenterprise.otel-default
| WHERE node_up IS NOT NULL
| STATS min_up = MIN(node_up) BY node, cluster
// Alert when any node reports as down (node_up < 1)
// A down node triggers automatic failover of its shards to replicas on other nodes
// Investigate host health, network connectivity, and management service status
| WHERE min_up < 1
